solution: ```class Solution {
    public boolean isValid(String s) {
        int n = s.length();
        if ((n & 1) == 1) return false;
        char[] stack = new char[n];
        int top = -1;
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            switch (c) {
                case '(':
                case '[':
                case '{':
                    stack[++top] = c;
                    break;
                case ')':
                    if (top == -1 || stack[top--] != '(') return false;
                    break;
                case ']':
                    if (top == -1 || stack[top--] != '[') return false;
                    break;
                case '}':
                    if (top == -1 || stack[top--] != '{') return false;
                    break;
            }
        }
        return top == -1;
    }
}
